`timescale 1ns / 1ps
`define DELAY 3

module reduce_tb;
    reg clk;
    reg rst;
    reg enable;
    reg [15:0] u [0:2][0:255];
    reg [15:0] v [0:255];
    wire reduce_done;
    wire [15:0] u_reduced [0:2][0:255];
    wire [15:0] v_reduced [0:255];

    reduce reduce_uut (
        .clk(clk),
        .rst(rst),
        .enable(enable),
        .u(u),
        .v(v),
        .reduce_done(reduce_done),
        .u_reduced(u_reduced),
        .v_reduced(v_reduced)
    );
initial begin
    $dumpfile("dump.vcd");
    $dumpvars(0, reduce_tb);
    clk = 0;
    forever #(`DELAY / 2) clk = ~clk;
end
integer i,j;
reg [15:0] coeff;


// Convert packed hex to 3D array
localparam int K = 3;
localparam int N = 256;

logic [12288-1:0] u_packed;
assign u_packed = 12288';

// Unpack u
// u = 256 * 16 * 3 bits
genvar k, l;
generate
for (k = 0; k < 3; k++) begin : UNPACK_POLY
    for (l = 0; l < 256; l++) begin : UNPACK_COEF
    assign u[k][l] = u_packed[12287 - (k*256 + l)*16 -: 16];
    end
end
endgenerate

// unpack v
// v = 256 * 16 bits
genvar m;
logic [4096-1:0] v_packed;
assign v_packed = 4096';
generate
for (m = 0; m < 256; m++) begin : UNPACK_V
    assign v[m] = v_packed[4095 - (m*16) -: 16];
end
endgenerate

initial begin
    // -- INPUT -- //
    rst = 1;
    // u = 256 * 16 * 3 bits
    // v = 256 * 16 bits

    //u = 12288';
    //v = 4096';
    enable = 0;

    // Release reset to start loading state_reg, done, etc
    #(`DELAY) rst = 0;
    #(`DELAY) enable = 1;

    wait (reduce_done == 1'b1);

    #(`DELAY * 10);

    $display(" poly u Before Reduction: ");
    for (j = 0; j < 3; j++) begin
        $display("=== u %0d ===", j);
        for (i = 0; i < 256; i++) begin
            coeff = u[j][i];
            $write("%0d ", coeff);
            if ((i % 16) == 15) $write("\n");
        end
        $write("\n");
        $display(" poly u After Reduction: ");
        $display("=== u %0d ===", j);
        for (i = 0; i < 256; i++) begin
            coeff = u_reduced[j][i];
            $write("%0d ", coeff);
            if ((i % 16) == 15) $write("\n");
        end
        $write("\n");
    end

    $display(" poly v Before Reduction: ");
    for (i = 0; i < 256; i++) begin
        coeff = v[i];
        $write("%0d ", coeff);
        if ((i % 16) == 15) $write("\n");
    end

    $display(" poly v After Reduction: ");
    for (i = 0; i < 256; i++) begin
        coeff = v_reduced[i];
        $write("%0d ", coeff);
        if ((i % 16) == 15) $write("\n");
    end
 end
endmodule